import React, {useEffect} from 'react'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'
import Sidebar from '../components/Sidebar'
import ListingCard from '../components/ListingCard'
import {useSelector, useDispatch} from 'react-redux'
import {shopSelector, getListing} from '../redux/shopSlice.js'

const ShopContentWrapper = styled.div `
width:80%;
margin:40px auto;
display:flex;

`

const SidebarWrapper = styled.div `
width:20%;
`

const Listings = styled.div `
width:80%;
display:flex;
flex-wrap: wrap;
justify-content: center;
`

export default function Shop () {
	const dispatch = useDispatch()
	const listing = useSelector(shopSelector)

	useEffect(() => {
		async function getListing () {
			const result = await fetch('http://localhost:5001/shop')
			const data = await result.json()
			dispatch(getListing(data[0]))
			//console.log(listing.listing.listing)
		}
		getListing ()
	},[])

	return (
		<>
			<Header />
			<Navbar />
			<ShopContentWrapper>
				<SidebarWrapper>
					<Sidebar />
				</SidebarWrapper>
				<Listings>
					<ListingCard />
					<ListingCard />
					<ListingCard />
					<ListingCard />
					<ListingCard />
					<ListingCard />
					<ListingCard />
					<ListingCard />
					<ListingCard />
					<ListingCard />
					<ListingCard />
					<ListingCard />
				</Listings>
			</ShopContentWrapper>
		</>
	)
}
